where deleted = 0 and status = 'READY'
and region_type = 'DOMESTIC'
and region_type = 'GLOBAL'
and category = #{category}
and source_id = #{sourceId}
and (title like concat('%', #{keyword}, '%') or title_zh like concat('%', #{keyword}, '%') or summary like concat('%', #{keyword}, '%') or summary_zh like concat('%', #{keyword}, '%'))

mapper.insert:
