    source_id, source_name, title, title_zh, summary, summary_zh, source_url, cover_image, language,
    region_type, category, tags_json, hot_score, publish_time, status, is_pinned, translation_status,
    ai_summary_status, deleted
) values (
    #{sourceId}, #{sourceName}, #{title}, #{titleZh}, #{summary}, #{summaryZh}, #{sourceUrl}, #{coverImage}, #{language},
    #{regionType}, #{category}, #{tagsJson}, #{hotScore}, #{publishTime}, #{status}, #{isPinned}, #{translationStatus},
    #{aiSummaryStatus}, #{deleted}
)

mapper.update:
